import { GoogleGenAI, Type, Modality } from "@google/genai";
import type { AnalysisResult, TestEvaluationResult, PracticeEvaluationResult } from '../types';

if (!process.env.API_KEY) {
    throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Transcribes audio with strict verbatim requirements.
 */
export const transcribeAudio = async (audioBase64: string, audioMimeType: string): Promise<string> => {
    const prompt = `You are a professional verbatim transcriber. 
    Transcribe the following audio EXACTLY as spoken. 
    - DO NOT correct grammar.
    - DO NOT paraphrase.
    - DO NOT add introductory text or summary.
    - DO NOT clean up filler words (um, ah) if they are clear.
    - Focus strictly on the words spoken.
    If no speech is detected, return exactly: "[No speech detected]"`;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: { parts: [{ inlineData: { data: audioBase64, mimeType: audioMimeType } }, { text: prompt }] },
        });
        return response.text.trim();
    } catch (error) {
        console.error("Error transcribing audio:", error);
        throw new Error("Failed to transcribe audio.");
    }
};

/**
 * Generates high-quality speech using Gemini TTS.
 */
export const generateSpeech = async (text: string, voice: string = 'Kore'): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text: `Say clearly: ${text}` }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: {
                        prebuiltVoiceConfig: { voiceName: voice },
                    },
                },
            },
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (!base64Audio) throw new Error("No audio data returned from Gemini TTS.");
        return base64Audio;
    } catch (error) {
        console.error("Error generating speech:", error);
        throw new Error("Failed to generate speech.");
    }
};

const keyMetricsSchema = {
    type: Type.OBJECT,
    properties: {
        grammarSuggestionsCount: { type: Type.INTEGER },
        relevanceRating: { type: Type.STRING },
        clarityRating: { type: Type.STRING }
    },
    required: ["grammarSuggestionsCount"]
};

const standardAnalysisSchema = {
    type: Type.OBJECT,
    properties: {
        keyMetrics: keyMetricsSchema,
        feedback: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    original: { type: Type.STRING },
                    correction: { type: Type.STRING },
                    explanation_vi: { type: Type.STRING }
                },
                 required: ["original", "correction", "explanation_vi"]
            }
        },
        improvedScript: { type: Type.STRING },
        answerExpansion: {
            type: Type.OBJECT,
            properties: {
                suggestions_vi: { type: Type.STRING },
                sample_extended_answer: { type: Type.STRING }
            },
            required: ["suggestions_vi", "sample_extended_answer"]
        }
    },
    required: ["keyMetrics", "feedback", "improvedScript"]
};

const advancedAnalysisSchema = {
    type: Type.OBJECT,
    properties: {
        keyMetrics: { ...keyMetricsSchema, required: ["grammarSuggestionsCount", "relevanceRating", "clarityRating"] },
        feedback: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    original: { type: Type.STRING },
                    correction: { type: Type.STRING },
                    explanation_vi: { type: Type.STRING }
                },
                 required: ["original", "correction", "explanation_vi"]
            }
        },
         relevanceFeedback: {
            type: Type.OBJECT,
            properties: { explanation_vi: { type: Type.STRING } },
            required: ["explanation_vi"]
        },
        clarityConcisenessFeedback: {
            type: Type.OBJECT,
            properties: {
                clarity_vi: { type: Type.STRING },
                conciseness_vi: { type: Type.STRING }
            },
            required: ["clarity_vi", "conciseness_vi"]
        },
        improvedScript: { type: Type.STRING }
    },
    required: ["keyMetrics", "feedback", "relevanceFeedback", "clarityConcisenessFeedback", "improvedScript"]
};

export const analyzeScript = async (script: string, question: string, analysisType: 'standard' | 'advanced'): Promise<AnalysisResult> => {
    const baseInstruction = "You are an expert English teacher. Focus strictly on the student's content.";
    const standardPrompt = `
    ${baseInstruction}
    Provide feedback on: "${script}" for question: "${question}".
    - Key Metrics: Count feedback items.
    - Improved Script: Fix grammar and flow. DO NOT add new sentences or outside information. Keep it to the point.
    - Expansion: ONLY if original is < 20 words.
    Response in JSON.`;

    const advancedPrompt = `
    ${baseInstruction} Specialist in IELTS.
    Provide detailed feedback on: "${script}" for question: "${question}".
    - Improved Script: Use Band 7.0+ vocabulary but preserve original ideas. DO NOT invent new facts.
    Response in JSON.`;

    const prompt = analysisType === 'advanced' ? advancedPrompt : standardPrompt;
    const schema = analysisType === 'advanced' ? advancedAnalysisSchema : standardAnalysisSchema;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-pro-preview",
            contents: prompt,
            config: { responseMimeType: "application/json", responseSchema: schema },
        });
        return JSON.parse(response.text.trim()) as AnalysisResult;
    } catch (error) {
        console.error("Error analyzing script:", error);
        throw new Error("Failed to get analysis.");
    }
};

export const getTestEvaluation = async (
    audioBase64: string, audioMimeType: string, question: string, evaluationType: 'standard' | 'advanced'
): Promise<TestEvaluationResult> => {
    const prompt = `Perform a strict IELTS evaluation. 
    1. Transcribe the audio verbatim. 
    2. Provide scores and feedback in Vietnamese. 
    3. IMPROVED SCRIPT: DO NOT add new information. Only refine the transcribed words for better grammar and vocabulary.
    Topic: "${question}"`;

    const testEvaluationSchema = {
        type: Type.OBJECT,
        properties: {
            overallScore: { type: Type.NUMBER },
            ieltsCriteriaFeedback: {
                type: Type.OBJECT,
                properties: {
                    fluency_vi: { type: Type.STRING },
                    lexicalResource_vi: { type: Type.STRING },
                    grammaticalRangeAndAccuracy_vi: { type: Type.STRING },
                    pronunciation_vi: { type: Type.STRING },
                },
                required: ["fluency_vi", "lexicalResource_vi", "grammaticalRangeAndAccuracy_vi", "pronunciation_vi"]
            },
            summary_vi: { type: Type.STRING },
            suggestions_vi: { type: Type.STRING },
            transcribedScript: { type: Type.STRING },
            improvedScript: { type: Type.STRING }
        },
        required: ["overallScore", "ieltsCriteriaFeedback", "summary_vi", "suggestions_vi", "transcribedScript", "improvedScript"]
    };

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-pro-preview",
            contents: { parts: [{ inlineData: { data: audioBase64, mimeType: audioMimeType } }, { text: prompt }] },
            config: { responseMimeType: "application/json", responseSchema: testEvaluationSchema },
        });
        return JSON.parse(response.text.trim()) as TestEvaluationResult;
    } catch (error) {
        console.error("Error getting test evaluation:", error);
        throw new Error("Failed to get test evaluation.");
    }
};

export const getPracticeEvaluation = async (audioBase64: string, audioMimeType: string, scriptToPractice: string): Promise<PracticeEvaluationResult> => {
    const prompt = `Evaluate the recording against this script: "${scriptToPractice}". 
    Focus on: Fluency, Pronunciation. Return score and Vietnamese summary.`;

    const practiceEvaluationSchema = {
        type: Type.OBJECT,
        properties: {
            overallScore: { type: Type.NUMBER },
            summary_vi: { type: Type.STRING }
        },
        required: ["overallScore", "summary_vi"]
    };

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: { parts: [{ inlineData: { data: audioBase64, mimeType: audioMimeType } }, { text: prompt }] },
            config: { responseMimeType: "application/json", responseSchema: practiceEvaluationSchema },
        });
        return JSON.parse(response.text.trim()) as PracticeEvaluationResult;
    } catch (error) {
        console.error("Error practice evaluation:", error);
        throw new Error("Failed practice evaluation.");
    }
};

import { useState, useCallback, useRef } from 'react';
import { generateSpeech } from '../services/geminiService';

interface SpeakOptions {
  voice?: string;
}

export interface VoiceOption {
  name: string;
  displayName: string;
}

interface TextToSpeechControls {
  speak: (text: string, options?: SpeakOptions) => Promise<void>;
  cancel: () => void;
  isSpeaking: boolean;
  isSupported: boolean;
  availableVoices: VoiceOption[];
  selectedVoiceName: string | null;
  setSelectedVoiceName: (name: string) => void;
}

// Utility to decode base64 into a Uint8Array
function decode(base64: string) {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
}

// Utility to decode raw PCM bytes to AudioBuffer
async function decodeAudioData(
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
): Promise<AudioBuffer> {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

    for (let channel = 0; channel < numChannels; channel++) {
        const channelData = buffer.getChannelData(channel);
        for (let i = 0; i < frameCount; i++) {
            channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
        }
    }
    return buffer;
}

export const useTextToSpeech = (): TextToSpeechControls => {
    const [isSpeaking, setIsSpeaking] = useState(false);
    const [selectedVoiceName, setSelectedVoiceName] = useState<string>('Kore');
    const audioContextRef = useRef<AudioContext | null>(null);
    const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);

    const availableVoices: VoiceOption[] = [
        { name: 'Kore', displayName: 'Kore (Male - Energetic)' },
        { name: 'Puck', displayName: 'Puck (Male - Calm)' },
        { name: 'Zephyr', displayName: 'Zephyr (Male - Natural)' },
        { name: 'Charon', displayName: 'Charon (Male - Deep)' }
    ];

    const cancel = useCallback(() => {
        if (currentSourceRef.current) {
            currentSourceRef.current.stop();
            currentSourceRef.current = null;
        }
        setIsSpeaking(false);
    }, []);

    const speak = useCallback(async (text: string, options: SpeakOptions = {}) => {
        if (!text || isSpeaking) return;

        setIsSpeaking(true);
        try {
            const voice = options.voice || selectedVoiceName;
            const base64Audio = await generateSpeech(text, voice);

            if (!audioContextRef.current) {
                audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
            }
            const ctx = audioContextRef.current;

            const audioBytes = decode(base64Audio);
            const audioBuffer = await decodeAudioData(audioBytes, ctx, 24000, 1);

            const source = ctx.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(ctx.destination);

            source.onended = () => {
                setIsSpeaking(false);
                currentSourceRef.current = null;
            };

            currentSourceRef.current = source;
            source.start(0);
        } catch (error) {
            console.error("Gemini TTS Error:", error);
            setIsSpeaking(false);
        }
    }, [isSpeaking, selectedVoiceName]);

    return {
        speak,
        cancel,
        isSpeaking,
        isSupported: true, // Always supported via Gemini API
        availableVoices,
        selectedVoiceName,
        setSelectedVoiceName
    };
};

import { useState, useRef, useCallback, useEffect } from 'react';

type RecorderState = 'inactive' | 'recording' | 'paused' | 'finished';

interface AudioRecorderControls {
  recorderState: RecorderState;
  audioURL: string | null;
  audioBlob: Blob | null;
  recordingTime: number;
  startRecording: () => void;
  stopRecording: () => void;
  resetRecording: () => void;
  error: string | null;
  mediaStream: MediaStream | null;
}

export const useAudioRecorder = ({ maxRecordingSeconds = 120 }: { maxRecordingSeconds?: number } = {}): AudioRecorderControls => {
  const [recorderState, setRecorderState] = useState<RecorderState>('inactive');
  const [audioURL, setAudioURL] = useState<string | null>(null);
  const [audioBlob, setAudioBlob] = useState<Blob | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [recordingTime, setRecordingTime] = useState(0);
  const [mediaStream, setMediaStream] = useState<MediaStream | null>(null);

  const mediaStreamRef = useRef<MediaStream | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerIntervalRef = useRef<number | null>(null);
  const stopTimeoutRef = useRef<number | null>(null);

  const cleanupTimer = useCallback(() => {
    if (timerIntervalRef.current) {
      clearInterval(timerIntervalRef.current);
      timerIntervalRef.current = null;
    }
    if (stopTimeoutRef.current) {
        clearTimeout(stopTimeoutRef.current);
        stopTimeoutRef.current = null;
    }
  }, []);

  const stopRecording = useCallback(() => {
    if (mediaRecorderRef.current && (recorderState === 'recording' || recorderState === 'paused')) {
      mediaRecorderRef.current.stop();
    }
    cleanupTimer();
  }, [recorderState, cleanupTimer]);


  const resetRecording = useCallback(() => {
    if (audioURL) {
      URL.revokeObjectURL(audioURL);
    }
    if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
        setMediaStream(null);
        mediaStreamRef.current = null;
    }
    setAudioURL(null);
    setAudioBlob(null);
    setRecorderState('inactive');
    audioChunksRef.current = [];
    setError(null);
    cleanupTimer();
    setRecordingTime(0);
  }, [audioURL, cleanupTimer]);

  const startRecording = async () => {
    resetRecording();
    setError(null);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;
      setMediaStream(stream);

      // Try multiple MIME types to ensure compatibility
      const mimeTypes = ['audio/webm', 'audio/ogg', 'audio/mp4'];
      let selectedMime = '';
      for (const m of mimeTypes) {
          if (MediaRecorder.isTypeSupported(m)) {
              selectedMime = m;
              break;
          }
      }

      const mediaRecorder = new MediaRecorder(stream, { mimeType: selectedMime });
      mediaRecorderRef.current = mediaRecorder;

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = () => {
        if (audioChunksRef.current.length === 0) {
            setError("No audio data captured. Please check your microphone.");
            setRecorderState('inactive');
            return;
        }

        const currentAudioBlob = new Blob(audioChunksRef.current, { type: selectedMime || 'audio/webm' });
        const url = URL.createObjectURL(currentAudioBlob);
        setAudioBlob(currentAudioBlob);
        setAudioURL(url);
        setRecorderState('finished');

        stream.getTracks().forEach(track => track.stop());
        setMediaStream(null);
        mediaStreamRef.current = null;
        cleanupTimer();
      };

      mediaRecorder.onerror = () => {
         setError('An error occurred during recording.');
         setRecorderState('inactive');
         stream.getTracks().forEach(track => track.stop());
         cleanupTimer();
      };

      mediaRecorder.start(100); // Collect data every 100ms
      setRecorderState('recording');

      timerIntervalRef.current = window.setInterval(() => {
        setRecordingTime(prevTime => prevTime + 1);
      }, 1000);

      stopTimeoutRef.current = window.setTimeout(stopRecording, maxRecordingSeconds * 1000);

    } catch (err) {
      console.error('Error:', err);
      setError('Could not access microphone.');
      setRecorderState('inactive');
    }
  };

  useEffect(() => {
    return () => {
      cleanupTimer();
      if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
      }
    };
  }, [cleanupTimer]);

  return { recorderState, audioURL, audioBlob, startRecording, stopRecording, resetRecording, error, recordingTime, mediaStream };
};

