/**
 * Transcribes audio with absolute verbatim requirements.
 * Focuses on preventing the AI from "inventing" content not present in the audio.
 */
export const transcribeAudio = async (audioBase64: string, audioMimeType: string): Promise<string> => {
    const prompt = `You are a strict verbatim transcription engine. 
    TASK: Transcribe the provided audio EXACTLY as spoken.
    RULES:
    - DO NOT add ANY words that were not spoken.
    - DO NOT fix grammar or punctuation while transcribing.
    - DO NOT summarize or paraphrase.
    - DO NOT guess or invent sentences if the audio is unclear; use "[unclear]" if a specific word is impossible to hear.
    - If there is only background noise or silence, return exactly: "[No speech detected]"
    - NO introductory or concluding remarks. Just the transcript.`;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: { parts: [{ inlineData: { data: audioBase64, mimeType: audioMimeType } }, { text: prompt }] },
        });
        const text = response.text?.trim() || "";
        return text || "[No speech detected]";
    } catch (error) {
        console.error("Error transcribing audio:", error);
        throw new Error("Failed to transcribe audio.");
    }
};

/**
 * Generates high-quality speech using Gemini TTS.
 */
export const generateSpeech = async (text: string, voice: string = 'Kore'): Promise<string> => {
    if (!text || text.trim().length === 0) {
        throw new Error("No text provided for speech generation.");
    }

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text: text }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: {
                        prebuiltVoiceConfig: { voiceName: voice },
                    },
                },
            },
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (!base64Audio) throw new Error("Audio generation returned empty data.");
        return base64Audio;
    } catch (error) {
        console.error("Error generating speech:", error);
        throw new Error("Failed to generate speech.");
    }
};

