import { useState, useCallback, useRef } from 'react';
import { generateSpeech } from '../services/geminiService';

interface SpeakOptions {
  voice?: string;
}

export interface VoiceOption {
  name: string;
  displayName: string;
}

interface TextToSpeechControls {
  speak: (text: string, options?: SpeakOptions) => Promise<void>;
  cancel: () => void;
  isSpeaking: boolean;
  isSupported: boolean;
  availableVoices: VoiceOption[];
  selectedVoiceName: string | null;
  setSelectedVoiceName: (name: string) => void;
}

// Utility to decode base64 into a Uint8Array
function decode(base64: string) {
    try {
        const binaryString = atob(base64);
        const len = binaryString.length;
        const bytes = new Uint8Array(len);
        for (let i = 0; i < len; i++) {
            bytes[i] = binaryString.charCodeAt(i);
        }
        return bytes;
    } catch (e) {
        console.error("Failed to decode base64 audio", e);
        return new Uint8Array(0);
    }
}

// Utility to decode raw PCM bytes to AudioBuffer
async function decodeAudioData(
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
): Promise<AudioBuffer> {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

    for (let channel = 0; channel < numChannels; channel++) {
        const channelData = buffer.getChannelData(channel);
        for (let i = 0; i < frameCount; i++) {
            // Normalize Int16 to Float32 [-1.0, 1.0]
            channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
        }
    }
    return buffer;
}

export const useTextToSpeech = (): TextToSpeechControls => {
    const [isSpeaking, setIsSpeaking] = useState(false);
    const [selectedVoiceName, setSelectedVoiceName] = useState<string>('Kore');
    const audioContextRef = useRef<AudioContext | null>(null);
    const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);

    const availableVoices: VoiceOption[] = [
        { name: 'Kore', displayName: 'Kore (Male - Energetic)' },
        { name: 'Puck', displayName: 'Puck (Male - Calm)' },
        { name: 'Zephyr', displayName: 'Zephyr (Male - Natural)' },
        { name: 'Charon', displayName: 'Charon (Male - Deep)' }
    ];

    const cancel = useCallback(() => {
        if (currentSourceRef.current) {
            try {
                currentSourceRef.current.stop();
            } catch (e) {
                // Ignore if already stopped
            }
            currentSourceRef.current = null;
        }
        setIsSpeaking(false);
    }, []);

    const speak = useCallback(async (text: string, options: SpeakOptions = {}) => {
        const cleanText = text?.trim();
        if (!cleanText || isSpeaking) return;

        setIsSpeaking(true);
        try {
            const voice = options.voice || selectedVoiceName;
            const base64Audio = await generateSpeech(cleanText, voice);

            if (!base64Audio) {
                throw new Error("Received empty audio data from API");
            }

            // Initialize or resume AudioContext (browser security requires user gesture)
            if (!audioContextRef.current) {
                audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
            }
            const ctx = audioContextRef.current;

            if (ctx.state === 'suspended') {
                await ctx.resume();
            }

            const audioBytes = decode(base64Audio);
            if (audioBytes.length === 0) {
                throw new Error("Decoded audio data is empty");
            }

            const audioBuffer = await decodeAudioData(audioBytes, ctx, 24000, 1);

            const source = ctx.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(ctx.destination);

            source.onended = () => {
                setIsSpeaking(false);
                currentSourceRef.current = null;
            };

            currentSourceRef.current = source;
            source.start(0);
        } catch (error) {
            console.error("Gemini TTS Error:", error);
            setIsSpeaking(false);
            alert("Sorry, we couldn't play the audio. Please try again.");
        }
    }, [isSpeaking, selectedVoiceName]);

    return {
        speak,
        cancel,
        isSpeaking,
        isSupported: true,
        availableVoices,
        selectedVoiceName,
        setSelectedVoiceName
    };
};

import { useState, useRef, useCallback, useEffect } from 'react';

type RecorderState = 'inactive' | 'recording' | 'paused' | 'finished';

interface AudioRecorderControls {
  recorderState: RecorderState;
  audioURL: string | null;
  audioBlob: Blob | null;
  recordingTime: number;
  startRecording: () => void;
  stopRecording: () => void;
  resetRecording: () => void;
  error: string | null;
  mediaStream: MediaStream | null;
}

export const useAudioRecorder = ({ maxRecordingSeconds = 120 }: { maxRecordingSeconds?: number } = {}): AudioRecorderControls => {
  const [recorderState, setRecorderState] = useState<RecorderState>('inactive');
  const [audioURL, setAudioURL] = useState<string | null>(null);
  const [audioBlob, setAudioBlob] = useState<Blob | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [recordingTime, setRecordingTime] = useState(0);
  const [mediaStream, setMediaStream] = useState<MediaStream | null>(null);

  const mediaStreamRef = useRef<MediaStream | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerIntervalRef = useRef<number | null>(null);
  const stopTimeoutRef = useRef<number | null>(null);

  const cleanupTimer = useCallback(() => {
    if (timerIntervalRef.current) {
      clearInterval(timerIntervalRef.current);
      timerIntervalRef.current = null;
    }
    if (stopTimeoutRef.current) {
        clearTimeout(stopTimeoutRef.current);
        stopTimeoutRef.current = null;
    }
  }, []);

  const stopRecording = useCallback(() => {
    if (mediaRecorderRef.current && (recorderState === 'recording' || recorderState === 'paused')) {
      mediaRecorderRef.current.stop();
    }
    cleanupTimer();
  }, [recorderState, cleanupTimer]);


  const resetRecording = useCallback(() => {
    if (audioURL) {
      URL.revokeObjectURL(audioURL);
    }
    if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
        setMediaStream(null);
        mediaStreamRef.current = null;
    }
    setAudioURL(null);
    setAudioBlob(null);
    setRecorderState('inactive');
    audioChunksRef.current = [];
    setError(null);
    cleanupTimer();
    setRecordingTime(0);
  }, [audioURL, cleanupTimer]);

  const startRecording = async () => {
    resetRecording();
    setError(null);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;
      setMediaStream(stream);

      // Preferred MIME types
      const mimeTypes = ['audio/webm', 'audio/ogg', 'audio/mp4', 'audio/wav'];
      let selectedMime = '';
      for (const m of mimeTypes) {
          if (MediaRecorder.isTypeSupported(m)) {
              selectedMime = m;
              break;
          }
      }

      const mediaRecorder = new MediaRecorder(stream, { mimeType: selectedMime });
      mediaRecorderRef.current = mediaRecorder;

      mediaRecorder.ondataavailable = (event) => {
        if (event.data && event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = () => {
        // Double check chunks
        const totalSize = audioChunksRef.current.reduce((acc, chunk) => acc + chunk.size, 0);

        if (totalSize === 0) {
            setError("No audio data captured. Please check your microphone and try again.");
            setRecorderState('inactive');
            return;
        }

        const currentAudioBlob = new Blob(audioChunksRef.current, { type: selectedMime || 'audio/webm' });
        const url = URL.createObjectURL(currentAudioBlob);
        setAudioBlob(currentAudioBlob);
        setAudioURL(url);
        setRecorderState('finished');

        // Stop all tracks to release the microphone
        if (mediaStreamRef.current) {
            mediaStreamRef.current.getTracks().forEach(track => track.stop());
            setMediaStream(null);
            mediaStreamRef.current = null;
        }
        cleanupTimer();
      };

      mediaRecorder.onerror = (event) => {
         console.error('Recorder error:', event);
         setError('An error occurred during recording.');
         setRecorderState('inactive');
         if (mediaStreamRef.current) {
            mediaStreamRef.current.getTracks().forEach(track => track.stop());
         }
         cleanupTimer();
      };

      mediaRecorder.start(250); // Small interval to ensure data collection
      setRecorderState('recording');

      timerIntervalRef.current = window.setInterval(() => {
        setRecordingTime(prevTime => prevTime + 1);
      }, 1000);

      stopTimeoutRef.current = window.setTimeout(stopRecording, maxRecordingSeconds * 1000);

    } catch (err) {
      console.error('Media access error:', err);
      setError('Could not access microphone. Please ensure permissions are granted.');
      setRecorderState('inactive');
    }
  };

  useEffect(() => {
    return () => {
      cleanupTimer();
      if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
      }
    };
  }, [cleanupTimer]);

  return { recorderState, audioURL, audioBlob, startRecording, stopRecording, resetRecording, error, recordingTime, mediaStream };
};

import React, { RefObject, useState, useEffect, useCallback } from 'react';
import Loader from './Loader';
import { useAudioRecorder } from '../hooks/useAudioRecorder';
import { MicIcon } from './icons/MicIcon';
import { StopIcon } from './icons/StopIcon';
import SoundWave from './SoundWave';
import { transcribeAudio } from '../services/geminiService';
import { blobToBase64, getFriendlyErrorMessage } from '../App';

interface ScriptInputProps {
  question: string;
  onQuestionChange: (value: string) => void;
  script: string;
  onScriptChange: (value: string) => void;
  onAnalyze: (analysisType: 'standard' | 'advanced') => void;
  isLoading: boolean;
  questionRef: RefObject<HTMLTextAreaElement>;
}

const ScriptInput: React.FC<ScriptInputProps> = ({ 
  question, onQuestionChange, 
  script, onScriptChange, 
  onAnalyze,
  isLoading, 
  questionRef
}) => {
  const [isTranscribing, setIsTranscribing] = useState(false);
  const [transcriptionError, setTranscriptionError] = useState<string | null>(null);

  const {
    recorderState,
    audioBlob,
    recordingTime,
    mediaStream,
    startRecording,
    stopRecording,
    error: recorderError
  } = useAudioRecorder({ maxRecordingSeconds: 120 });

  const transcribeRecording = useCallback(async (blob: Blob) => {
      setIsTranscribing(true);
      setTranscriptionError(null);
      onScriptChange(''); // Clear previous script
      try {
          const base64 = await blobToBase64(blob);
          const transcript = await transcribeAudio(base64, blob.type);

          if (transcript === "[No speech detected]") {
              setTranscriptionError("AI did not detect any speech in your recording. Please try speaking closer to the microphone.");
          } else {
              onScriptChange(transcript);
          }
      } catch (err) {
          setTranscriptionError(getFriendlyErrorMessage(err));
          onScriptChange(''); // Clear script on error
      } finally {
          setIsTranscribing(false);
      }
  }, [onScriptChange]);

  useEffect(() => {
    if (recorderState === 'finished' && audioBlob) {
        transcribeRecording(audioBlob);
    }
  }, [recorderState, audioBlob, transcribeRecording]);

  const handleStartRecording = () => {
    onScriptChange('');
    setTranscriptionError(null);
    startRecording();
  };

  const formatTime = (seconds: number): string => {
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes.toString().padStart(2, '0')}:${remainingSeconds.toString().padStart(2, '0')}`;
  };

  const isSubmitDisabled = isLoading || !script.trim() || !question.trim() || isTranscribing || recorderState === 'recording';

  const renderAnalysisButtons = () => (
    <div className="mt-6 flex flex-col sm:flex-row gap-4">
        <div className="w-full">
          <button
            onClick={() => onAnalyze('standard')}
            disabled={isSubmitDisabled}
            className="w-full flex justify-center items-center bg-success text-white font-bold py-3 px-4 rounded-lg hover:bg-green-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-success disabled:bg-gray-400 disabled:cursor-not-allowed transition duration-200"
          >
            {isLoading ? <Loader /> : 'Standard Analysis'}
