import React, { RefObject, useState, useEffect, useCallback, useRef } from 'react';
import Loader from './Loader';
import { useAudioRecorder } from '../hooks/useAudioRecorder';
import { MicIcon } from './icons/MicIcon';
import { StopIcon } from './icons/StopIcon';
import SoundWave from './SoundWave';
import { transcribeAudio } from '../services/geminiService';
import { blobToBase64, getFriendlyErrorMessage } from '../App';

interface ScriptInputProps {
  question: string;
  onQuestionChange: (value: string) => void;
  script: string;
  onScriptChange: (value: string) => void;
  onAnalyze: (analysisType: 'standard' | 'advanced') => void;
  isLoading: boolean;
  questionRef: RefObject<HTMLTextAreaElement>;
}

const UploadIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg>
);

const ScriptInput: React.FC<ScriptInputProps> = ({ 
  question, onQuestionChange, 
  script, onScriptChange, 
  onAnalyze,
  isLoading, 
  questionRef
}) => {
  const [isTranscribing, setIsTranscribing] = useState(false);
  const [transcriptionError, setTranscriptionError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const {
    recorderState,
    audioBlob,
    recordingTime,
    mediaStream,
    startRecording,
    stopRecording,
    error: recorderError
  } = useAudioRecorder({ maxRecordingSeconds: 120 });

  const transcribeRecording = useCallback(async (blob: Blob) => {
      setIsTranscribing(true);
      setTranscriptionError(null);
      onScriptChange(''); // Clear previous script
      try {
          const base64 = await blobToBase64(blob);
          const transcript = await transcribeAudio(base64, blob.type);

          if (transcript === "[No speech detected]") {
              setTranscriptionError("AI did not detect any speech in your audio. Please try a clearer recording.");
          } else {
              onScriptChange(transcript);
          }
      } catch (err) {
          setTranscriptionError(getFriendlyErrorMessage(err));
          onScriptChange(''); // Clear script on error
      } finally {
          setIsTranscribing(false);
      }
  }, [onScriptChange]);

  useEffect(() => {
    if (recorderState === 'finished' && audioBlob) {
        transcribeRecording(audioBlob);
    }
  }, [recorderState, audioBlob, transcribeRecording]);

  const handleStartRecording = () => {
    onScriptChange('');
    setTranscriptionError(null);
    startRecording();
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
        if (!file.type.startsWith('audio/')) {
            setTranscriptionError("Please upload a valid audio file.");
            return;
        }
        transcribeRecording(file);
    }
    // Reset input so the same file can be selected again if needed
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const formatTime = (seconds: number): string => {
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes.toString().padStart(2, '0')}:${remainingSeconds.toString().padStart(2, '0')}`;
  };

  const isSubmitDisabled = isLoading || !script.trim() || !question.trim() || isTranscribing || recorderState === 'recording';

  const renderAnalysisButtons = () => (
    <div className="mt-6 flex flex-col sm:flex-row gap-4">
        <div className="w-full">
          <button
            onClick={() => onAnalyze('standard')}
            disabled={isSubmitDisabled}
            className="w-full flex justify-center items-center bg-success text-white font-bold py-3 px-4 rounded-lg hover:bg-green-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-success disabled:bg-gray-400 disabled:cursor-not-allowed transition duration-200"
          >
            {isLoading ? <Loader /> : 'Standard Analysis'}
          </button>
          <p className="text-xs text-secondary mt-2 px-1 text-center sm:text-left">
            Phân tích phù hợp cho trình độ trung bình, tập trung vào ngữ pháp và diễn đạt tự nhiên.
          </p>
        </div>
        <div className="w-full">
          <button
            onClick={() => onAnalyze('advanced')}
            disabled={isSubmitDisabled}
            className="w-full flex justify-center items-center bg-white border border-secondary text-secondary font-bold py-3 px-4 rounded-lg hover:bg-secondary/10 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-secondary disabled:bg-gray-400 disabled:text-white disabled:border-gray-400 disabled:cursor-not-allowed transition duration-200"
          >
            {isLoading ? <Loader /> : 'Advanced Analysis'}
          </button>
           <p className="text-xs text-secondary mt-2 px-1 text-center sm:text-left">
            Phân tích chuyên sâu (IELTS), nâng cấp từ vựng và cấu trúc Band 7.0+.
          </p>
        </div>
    </div>
  );

  return (
    <div className="bg-white p-6 rounded-xl shadow-lg">
      <h2 className="text-2xl font-semibold mb-4 text-dark">
        1. Question & Spoken Answer
      </h2>
      <p className="text-secondary mb-4">
        Enter your question, then record or upload your response. AI will transcribe it for you.
      </p>

      <div className="mb-4">
        <label htmlFor="question-input" className="block text-sm font-medium text-gray-700 mb-1">Question</label>
        <textarea
          ref={questionRef}
          id="question-input"
          value={question}
          onChange={(e) => onQuestionChange(e.target.value)}
          placeholder="E.g., What did you do on your last holiday?"
          className="w-full h-24 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary focus:border-transparent transition duration-200 resize-y"
          disabled={isLoading || recorderState === 'recording' || isTranscribing}
        />
      </div>

      <div className="mt-4 border-t pt-6">
        <h3 className="text-xl font-semibold mb-2 text-dark">2. Provide Your Answer</h3>
        <p className="text-secondary mb-4">Record live or upload your own audio file to be transcribed.</p>

        <div className="p-4 bg-gray-100 rounded-lg">
            <div className="flex flex-col md:flex-row items-center gap-4">
                {recorderState === 'recording' ? (
                    <div className="w-full flex flex-col sm:flex-row items-center gap-4">
                        <button onClick={stopRecording} className="flex items-center justify-center w-full sm:w-auto gap-2 px-6 py-3 bg-danger text-white font-bold rounded-lg hover:bg-red-600 transition duration-200 shrink-0 animate-pulse-red">
                            <StopIcon />
                            <span>Stop Recording</span>
                            <div className="flex items-center gap-1.5 ml-2 bg-black/20 px-2 py-0.5 rounded-md">
                                <span className="font-mono text-sm tracking-wider">{formatTime(recordingTime)}</span>
                            </div>
                        </button>
                        {mediaStream && <SoundWave 
                            mediaStream={mediaStream} 
                            width={200} 
                            height={50}
                            baseColor="#FCA5A5"   
                            activeColor="#DC3545" 
                        />}
                    </div>
                ) : (
                    <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
                        <button onClick={handleStartRecording} disabled={isLoading || isTranscribing} className="flex items-center justify-center gap-2 px-6 py-3 bg-primary text-white font-bold rounded-lg hover:bg-blue-600 transition duration-200 disabled:bg-gray-400 whitespace-nowrap">
                            <MicIcon />
                            {isTranscribing ? 'Processing...' : 'Start Recording'}
                        </button>

                        <button 
                            onClick={() => fileInputRef.current?.click()} 
                            disabled={isLoading || isTranscribing} 
                            className="flex items-center justify-center gap-2 px-6 py-3 bg-white border-2 border-primary text-primary font-bold rounded-lg hover:bg-primary/5 transition duration-200 disabled:border-gray-400 disabled:text-gray-400 whitespace-nowrap"
                        >
                            <UploadIcon />
                            <span>Upload Audio</span>
                        </button>

                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            className="hidden" 
                            accept="audio/*" 
                            onChange={handleFileUpload}
                        />
                    </div>
                )}
                {isTranscribing && <Loader className="w-6 h-6 text-primary ml-2" />}
            </div>

            {(recorderError || transcriptionError) && (
              <div className="mt-4 p-3 bg-red-100 text-red-700 rounded-lg text-sm">
                {recorderError || transcriptionError}
              </div>
            )}

            {script && !isTranscribing && (
                <div className="mt-4 p-4 bg-white border border-gray-200 rounded-lg">
                    <div className="flex justify-between items-center mb-1">
                        <h4 className="text-sm font-bold text-secondary">Transcribed Text:</h4>
                        <span className="text-[10px] uppercase font-bold text-primary bg-primary/10 px-2 py-0.5 rounded">Smart Transcript</span>
                    </div>
                    <p className="text-dark italic">{script}</p>
                </div>
            )}
        </div>

        <h3 className="text-xl font-semibold mb-2 mt-6 text-dark">3. Get Analysis</h3>
        <p className="text-secondary mb-4">Select an analysis type to see improvements and feedback.</p>
        {renderAnalysisButtons()}
      </div>
    </div>
  );
};

