    properties: {
        grammarSuggestionsCount: { type: Type.INTEGER },
        relevanceRating: { type: Type.STRING },
        clarityRating: { type: Type.STRING }
    },
    required: ["grammarSuggestionsCount"]
};

const standardAnalysisSchema = {
    type: Type.OBJECT,
    properties: {
        keyMetrics: keyMetricsSchema,
        feedback: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    original: { type: Type.STRING },
                    correction: { type: Type.STRING },
                    explanation_vi: { type: Type.STRING }
                },
                 required: ["original", "correction", "explanation_vi"]
            }
        },
        improvedScript: { type: Type.STRING },
        answerExpansion: {
            type: Type.OBJECT,
            properties: {
                suggestions_vi: { type: Type.STRING },
                sample_extended_answer: { type: Type.STRING }
            },
            required: ["suggestions_vi", "sample_extended_answer"]
        }
    },
    required: ["keyMetrics", "feedback", "improvedScript"]
};

const advancedAnalysisSchema = {
    type: Type.OBJECT,
    properties: {
        keyMetrics: { ...keyMetricsSchema, required: ["grammarSuggestionsCount", "relevanceRating", "clarityRating"] },
        feedback: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    original: { type: Type.STRING },
                    correction: { type: Type.STRING },
                    explanation_vi: { type: Type.STRING }
                },
                 required: ["original", "correction", "explanation_vi"]
            }
        },
         relevanceFeedback: {
            type: Type.OBJECT,
            properties: { explanation_vi: { type: Type.STRING } },
            required: ["explanation_vi"]
        },
        clarityConcisenessFeedback: {
            type: Type.OBJECT,
            properties: {
                clarity_vi: { type: Type.STRING },
                conciseness_vi: { type: Type.STRING }
            },
            required: ["clarity_vi", "conciseness_vi"]
        },
        improvedScript: { type: Type.STRING }
    },
    required: ["keyMetrics", "feedback", "relevanceFeedback", "clarityConcisenessFeedback", "improvedScript"]
};

export const analyzeScript = async (script: string, question: string, analysisType: 'standard' | 'advanced'): Promise<AnalysisResult> => {
    const baseInstruction = "You are an expert English teacher specializing in IELTS. Your goal is to improve the student's script WITHOUT adding new information.";

    const prompt = `
    ${baseInstruction}
    Question: "${question}"
    Student's Script: "${script}"

    STRICT IMPROVEMENT RULES:
    1. The "improvedScript" MUST contain only the student's original ideas. 
    2. DO NOT add new sentences, new facts, or extra details that weren't in the original.
    3. ONLY correct grammar, improve vocabulary choices, and refine phrasing to sound natural.
    4. Provide feedback in Vietnamese (explanation_vi).
    5. Result must be valid JSON following the schema.`;

    const schema = analysisType === 'advanced' ? advancedAnalysisSchema : standardAnalysisSchema;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-pro-preview",
            contents: prompt,
            config: { responseMimeType: "application/json", responseSchema: schema },
        });
        return JSON.parse(response.text.trim()) as AnalysisResult;
    } catch (error) {
        console.error("Error analyzing script:", error);
        throw new Error("Failed to get analysis.");
    }
};

export const getTestEvaluation = async (
    audioBase64: string, audioMimeType: string, question: string, evaluationType: 'standard' | 'advanced'
): Promise<TestEvaluationResult> => {
    const prompt = `Perform a strict IELTS evaluation based on the provided audio.
    1. TRANSCRIBE: Output exactly what the student says. Do not fix anything here.
    2. EVALUATE: Provide an overall score on a scale of 0 to 100 (where 100 is equivalent to a perfect IELTS Band 9.0).
    3. FEEDBACK: Provide detailed feedback for each IELTS criteria in Vietnamese.
    4. IMPROVED SCRIPT: Refine the student's spoken words for better grammar and flow.
       - CRITICAL: DO NOT add ANY information, facts, or sentences not present in the audio.
       - Keep the student's message identical, just make the English correct.
    Topic: "${question}"`;

    const testEvaluationSchema = {
        type: Type.OBJECT,
        properties: {
            overallScore: { type: Type.NUMBER, description: "A score from 0 to 100 based on IELTS criteria mapping (e.g., Band 7.0 = 78, Band 8.0 = 89, Band 9.0 = 100)." },
            ieltsCriteriaFeedback: {
                type: Type.OBJECT,
                properties: {
                    fluency_vi: { type: Type.STRING },
                    lexicalResource_vi: { type: Type.STRING },
                    grammaticalRangeAndAccuracy_vi: { type: Type.STRING },
                    pronunciation_vi: { type: Type.STRING },
                },
                required: ["fluency_vi", "lexicalResource_vi", "grammaticalRangeAndAccuracy_vi", "pronunciation_vi"]
            },
            summary_vi: { type: Type.STRING },
            suggestions_vi: { type: Type.STRING },
            transcribedScript: { type: Type.STRING },
            improvedScript: { type: Type.STRING }
        },
        required: ["overallScore", "ieltsCriteriaFeedback", "summary_vi", "suggestions_vi", "transcribedScript", "improvedScript"]
    };

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-pro-preview",
            contents: { parts: [{ inlineData: { data: audioBase64, mimeType: audioMimeType } }, { text: prompt }] },
            config: { responseMimeType: "application/json", responseSchema: testEvaluationSchema },
        });
        return JSON.parse(response.text.trim()) as TestEvaluationResult;
    } catch (error) {
        console.error("Error getting test evaluation:", error);
        throw new Error("Failed to get test evaluation.");
    }
};

export const getPracticeEvaluation = async (audioBase64: string, audioMimeType: string, scriptToPractice: string): Promise<PracticeEvaluationResult> => {
    const prompt = `Compare the student's recording to this target script: "${scriptToPractice}". 
    Evaluate their accuracy, fluency, and pronunciation. 
    Return a score (0-100) and a concise summary in Vietnamese.`;

    const practiceEvaluationSchema = {
        type: Type.OBJECT,
        properties: {
            overallScore: { type: Type.NUMBER },
            summary_vi: { type: Type.STRING }
        },
        required: ["overallScore", "summary_vi"]
    };

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: { parts: [{ inlineData: { data: audioBase64, mimeType: audioMimeType } }, { text: prompt }] },
            config: { responseMimeType: "application/json", responseSchema: practiceEvaluationSchema },
        });
        return JSON.parse(response.text.trim()) as PracticeEvaluationResult;
    } catch (error) {
        console.error("Error practice evaluation:", error);
        throw new Error("Failed practice evaluation.");
    }
};

import React, { RefObject, useState, useEffect, useCallback, useRef } from 'react';
import Loader from './Loader';
import { useAudioRecorder } from '../hooks/useAudioRecorder';
import { MicIcon } from './icons/MicIcon';
import { StopIcon } from './icons/StopIcon';
import SoundWave from './SoundWave';
import { transcribeAudio } from '../services/geminiService';
import { blobToBase64, getFriendlyErrorMessage } from '../App';

interface ScriptInputProps {
  question: string;
  onQuestionChange: (value: string) => void;
  script: string;
  onScriptChange: (value: string) => void;
  onAnalyze: (analysisType: 'standard' | 'advanced') => void;
  isLoading: boolean;
  questionRef: RefObject<HTMLTextAreaElement>;
}

const UploadIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg>
);

const DownloadIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
);

const ScriptInput: React.FC<ScriptInputProps> = ({ 
  question, onQuestionChange, 
  script, onScriptChange, 
  onAnalyze,
  isLoading, 
  questionRef
}) => {
  const [isTranscribing, setIsTranscribing] = useState(false);
  const [transcriptionError, setTranscriptionError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const {
    recorderState,
    audioBlob,
    audioURL,
    recordingTime,
    mediaStream,
    startRecording,
    stopRecording,
    error: recorderError
  } = useAudioRecorder({ maxRecordingSeconds: 120 });

  const transcribeRecording = useCallback(async (blob: Blob) => {
      setIsTranscribing(true);
      setTranscriptionError(null);
      onScriptChange(''); // Clear previous script
      try {
          const base64 = await blobToBase64(blob);
          const transcript = await transcribeAudio(base64, blob.type);

          if (transcript === "[No speech detected]") {
              setTranscriptionError("AI did not detect any speech in your audio. Please try a clearer recording.");
          } else {
              onScriptChange(transcript);
          }
      } catch (err) {
          setTranscriptionError(getFriendlyErrorMessage(err));
          onScriptChange(''); // Clear script on error
      } finally {
          setIsTranscribing(false);
      }
  }, [onScriptChange]);

  useEffect(() => {
    if (recorderState === 'finished' && audioBlob) {
        transcribeRecording(audioBlob);
    }
  }, [recorderState, audioBlob, transcribeRecording]);

  const handleStartRecording = () => {
    onScriptChange('');
    setTranscriptionError(null);
    startRecording();
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
        if (!file.type.startsWith('audio/')) {
            setTranscriptionError("Please upload a valid audio file.");
            return;
        }
        transcribeRecording(file);
    }
    // Reset input so the same file can be selected again if needed
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const formatTime = (seconds: number): string => {
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes.toString().padStart(2, '0')}:${remainingSeconds.toString().padStart(2, '0')}`;
  };

  const isSubmitDisabled = isLoading || !script.trim() || !question.trim() || isTranscribing || recorderState === 'recording';

  const renderAnalysisButtons = () => (
    <div className="mt-6 flex flex-col sm:flex-row gap-4">
        <div className="w-full">
          <button
            onClick={() => onAnalyze('standard')}
            disabled={isSubmitDisabled}
            className="w-full flex justify-center items-center bg-success text-white font-bold py-3 px-4 rounded-lg hover:bg-green-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-success disabled:bg-gray-400 disabled:cursor-not-allowed transition duration-200"
          >
            {isLoading ? <Loader /> : 'Standard Analysis'}
          </button>
          <p className="text-xs text-secondary mt-2 px-1 text-center sm:text-left">
            Phân tích phù hợp cho trình độ trung bình, tập trung vào ngữ pháp và diễn đạt tự nhiên.
          </p>
        </div>
        <div className="w-full">
          <button
            onClick={() => onAnalyze('advanced')}
            disabled={isSubmitDisabled}
            className="w-full flex justify-center items-center bg-white border border-secondary text-secondary font-bold py-3 px-4 rounded-lg hover:bg-secondary/10 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-secondary disabled:bg-gray-400 disabled:text-white disabled:border-gray-400 disabled:cursor-not-allowed transition duration-200"
          >
            {isLoading ? <Loader /> : 'Advanced Analysis'}
          </button>
           <p className="text-xs text-secondary mt-2 px-1 text-center sm:text-left">
            Phân tích chuyên sâu (IELTS), nâng cấp từ vựng và cấu trúc Band 7.0+.
          </p>
        </div>
    </div>
  );

  return (
    <div className="bg-white p-6 rounded-xl shadow-lg">
      <h2 className="text-2xl font-semibold mb-4 text-dark">
        1. Question & Spoken Answer
      </h2>
      <p className="text-secondary mb-4">
        Enter your question, then record or upload your response. AI will transcribe it for you.
      </p>

      <div className="mb-4">
        <label htmlFor="question-input" className="block text-sm font-medium text-gray-700 mb-1">Question</label>
        <textarea
          ref={questionRef}
          id="question-input"
          value={question}
          onChange={(e) => onQuestionChange(e.target.value)}
          placeholder="E.g., What did you do on your last holiday?"
          className="w-full h-24 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary focus:border-transparent transition duration-200 resize-y"
          disabled={isLoading || recorderState === 'recording' || isTranscribing}
        />
      </div>

      <div className="mt-4 border-t pt-6">
        <h3 className="text-xl font-semibold mb-2 text-dark">2. Provide Your Answer</h3>
        <p className="text-secondary mb-4">Record live or upload your own audio file to be transcribed.</p>

        <div className="p-4 bg-gray-100 rounded-lg">
            <div className="flex flex-col md:flex-row items-center gap-4">
                {recorderState === 'recording' ? (
                    <div className="w-full flex flex-col sm:flex-row items-center gap-4">
                        <button onClick={stopRecording} className="flex items-center justify-center w-full sm:w-auto gap-2 px-6 py-3 bg-danger text-white font-bold rounded-lg hover:bg-red-600 transition duration-200 shrink-0 animate-pulse-red">
                            <StopIcon />
                            <span>Stop Recording</span>
                            <div className="flex items-center gap-1.5 ml-2 bg-black/20 px-2 py-0.5 rounded-md">
                                <span className="font-mono text-sm tracking-wider">{formatTime(recordingTime)}</span>
                            </div>
                        </button>
                        {mediaStream && <SoundWave 
                            mediaStream={mediaStream} 
                            width={200} 
                            height={50}
                            baseColor="#FCA5A5"   
                            activeColor="#DC3545" 
                        />}
                    </div>
                ) : (
                    <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
                        <button onClick={handleStartRecording} disabled={isLoading || isTranscribing} className="flex items-center justify-center gap-2 px-6 py-3 bg-primary text-white font-bold rounded-lg hover:bg-blue-600 transition duration-200 disabled:bg-gray-400 whitespace-nowrap">
                            <MicIcon />
                            {isTranscribing ? 'Processing...' : 'Start Recording'}
                        </button>

                        <button 
                            onClick={() => fileInputRef.current?.click()} 
                            disabled={isLoading || isTranscribing} 
                            className="flex items-center justify-center gap-2 px-6 py-3 bg-white border-2 border-primary text-primary font-bold rounded-lg hover:bg-primary/5 transition duration-200 disabled:border-gray-400 disabled:text-gray-400 whitespace-nowrap"
                        >
                            <UploadIcon />
                            <span>Upload Audio</span>
                        </button>

                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            className="hidden" 
                            accept="audio/*" 
                            onChange={handleFileUpload}
                        />
                    </div>
                )}
                {isTranscribing && <Loader className="w-6 h-6 text-primary ml-2" />}
            </div>

            {(recorderError || transcriptionError) && (
              <div className="mt-4 p-3 bg-red-100 text-red-700 rounded-lg text-sm">
                {recorderError || transcriptionError}
              </div>
            )}

            {script && !isTranscribing && (
                <div className="mt-4 p-4 bg-white border border-gray-200 rounded-lg">
                    <div className="flex justify-between items-center mb-1">
                        <div className="flex items-center gap-2">
                           <h4 className="text-sm font-bold text-secondary">Transcribed Text:</h4>
                           {audioURL && (
                             <a 
                               href={audioURL} 
                               download="my-recording.webm" 
                               className="flex items-center gap-1 text-[10px] text-primary hover:underline font-bold"
                               title="Tải audio vừa ghi âm"
                             >
                               <DownloadIcon />
                               Download Audio
                             </a>
                           )}
                        </div>
                        <span className="text-[10px] uppercase font-bold text-primary bg-primary/10 px-2 py-0.5 rounded">Smart Transcript</span>
                    </div>
                    <p className="text-dark italic">{script}</p>
                </div>
            )}
        </div>

        <h3 className="text-xl font-semibold mb-2 mt-6 text-dark">3. Get Analysis</h3>
        <p className="text-secondary mb-4">Select an analysis type to see improvements and feedback.</p>
        {renderAnalysisButtons()}
      </div>
    </div>
  );
};

export default ScriptInput;

import React from 'react';
import { useAudioRecorder } from '../hooks/useAudioRecorder';
import type { PracticeEvaluationResult } from '../types';
import Loader from './Loader';
import { MicIcon } from './icons/MicIcon';
import { StopIcon } from './icons/StopIcon';
import SoundWave from './SoundWave';
import ScoreCircle from './ScoreCircle';

interface PronunciationPracticeProps {
  scriptToPractice: string;
  onGetPracticeEvaluation: (audioBlob: Blob) => void;
  onResetPracticeEvaluation: () => void;
  practiceEvaluationResult: PracticeEvaluationResult | null;
  isPracticeEvaluating: boolean;
  testPart: 'part1' | 'part2' | 'part3' | null;
}

const DownloadIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
);

const PronunciationPractice: React.FC<PronunciationPracticeProps> = ({ 
    scriptToPractice, 
    onGetPracticeEvaluation,
    onResetPracticeEvaluation,
    practiceEvaluationResult,
    isPracticeEvaluating,
    testPart
}) => {
  const { maxRecordingSeconds, maxRecordingTimeText } = React.useMemo(() => {
    switch(testPart) {
      case 'part1': return { maxRecordingSeconds: 45, maxRecordingTimeText: '45 seconds' };
      case 'part3': return { maxRecordingSeconds: 90, maxRecordingTimeText: '1 minute 30 seconds' };
      case 'part2':
      default:
        return { maxRecordingSeconds: 120, maxRecordingTimeText: '2 minutes' };
    }
  }, [testPart]);

  const { recorderState, audioBlob, audioURL, startRecording, stopRecording, error, recordingTime, mediaStream } = useAudioRecorder({ maxRecordingSeconds });

  const handleGetScore = () => {
    if (audioBlob) {
        onGetPracticeEvaluation(audioBlob);
    }
  };

  const handleStartRecording = () => {
    onResetPracticeEvaluation();
    startRecording();
  };

  const formatTime = (seconds: number): string => {
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes.toString().padStart(2, '0')}:${remainingSeconds.toString().padStart(2, '0')}`;
  };

  const isActionDisabled = isPracticeEvaluating || !audioBlob || recorderState !== 'finished';

  return (
    <div className="mt-8 bg-white p-6 rounded-xl shadow-lg animate-fade-in">
      <h2 className="text-2xl font-semibold mb-4 text-dark">3. Practice &amp; Get Score</h2>

      {!practiceEvaluationResult && (
          <>
            <div className="border-t pt-6">
                <div className="flex justify-between items-center">
                    <h4 className="text-lg font-semibold text-dark mb-2">Record Your Practice</h4>
                    <p className="text-xs text-secondary font-medium bg-gray-100 px-2 py-1 rounded">Max recording time: {maxRecordingTimeText}</p>
                </div>
                <p className="text-secondary mb-4 text-sm">
                    Practice reading the AI's improved script from the section above, then get a performance score based on your delivery.
                </p>
                <div className="p-4 bg-gray-100 rounded-lg">
                    <div className="flex flex-col sm:flex-row items-center gap-4">
                        {recorderState === 'recording' ? (
                            <div className="w-full flex flex-col sm:flex-row items-center gap-4">
                                <button onClick={stopRecording} className="flex items-center justify-center w-full sm:w-auto gap-2 px-6 py-3 bg-danger text-white font-bold rounded-lg hover:bg-red-600 transition duration-200 shrink-0 animate-pulse-red">
                                    <StopIcon />
                                    <span>Stop Recording</span>
                                    <div className="flex items-center gap-1.5 ml-2 bg-black/20 px-2 py-0.5 rounded-md">
                                        <span className="font-mono text-sm tracking-wider">{formatTime(recordingTime)}</span>
                                    </div>
                                </button>
                                {mediaStream && <SoundWave 
                                    mediaStream={mediaStream} 
                                    width={200} 
                                    height={50} 
                                    baseColor="#FCA5A5"   
                                    activeColor="#DC3545"
                                />}
                            </div>
                        ) : (
                            <div className="flex items-center gap-3">
                              <button onClick={handleStartRecording} disabled={isPracticeEvaluating} className="flex items-center justify-center w-full sm:w-auto gap-2 px-6 py-3 bg-primary text-white font-bold rounded-lg hover:bg-blue-600 transition duration-200 shrink-0 disabled:bg-gray-400">
                                  <MicIcon />
                                  {recorderState === 'finished' ? 'Record Again' : 'Start Recording'}
                              </button>
                              {recorderState === 'finished' && audioURL && (
                                <a 
                                  href={audioURL} 
                                  download="practice-recording.webm"
                                  className="flex items-center justify-center gap-2 px-4 py-3 bg-white border border-secondary text-secondary font-bold rounded-lg hover:bg-gray-50 transition duration-200"
                                  title="Tải audio vừa luyện tập"
                                >
                                  <DownloadIcon />
                                  <span>Download</span>
                                </a>
                              )}
                            </div>
                        )}

                        {recorderState === 'finished' && audioBlob && (
                            <div className="p-2 text-center bg-green-100 text-green-800 text-sm font-semibold rounded-lg w-full">
                                Recording finished! Click below to get your score.
                            </div>
                        )}
                    </div>

                    {error && (
                        <div className="mt-3 text-red-600 text-sm" role="alert">
                            {error}
                        </div>
                    )}
                </div>
            </div>

            <div className="mt-6 border-t pt-6">
                    <p className="text-secondary mb-3 text-sm">When you're happy with your recording, click the button below to get your performance score.</p>
                     <button
                        onClick={handleGetScore}
                        disabled={isActionDisabled || !!practiceEvaluationResult}
                        className="w-full flex justify-center items-center bg-primary text-white font-bold py-3 px-6 rounded-lg hover:bg-blue-600 disabled:bg-gray-400 disabled:cursor-not-allowed transition duration-200"
                    >
                        {isPracticeEvaluating ? <Loader /> : 'Get Performance Score'}
                    </button>
            </div>
        </>
      )}

      {isPracticeEvaluating && !practiceEvaluationResult && (
            <div className="mt-8 flex flex-col items-center justify-center p-6">
                <Loader className="w-10 h-10 text-primary" />
                <p className="mt-4 text-secondary font-medium">Evaluating performance...</p>
            </div>
      )}

      {practiceEvaluationResult && (
        <div className="mt-8 p-6 bg-indigo-50 border-t-4 border-indigo-500 rounded-b-xl shadow-lg animate-fade-in">
            <h3 className="text-2xl font-bold text-indigo-800 mb-4 text-center">Practice Performance Score</h3>
            <div className="flex flex-col md:flex-row items-center gap-6">
                <div className="flex-shrink-0">
                    <ScoreCircle score={practiceEvaluationResult.overallScore} />
                </div>
                <div className="flex-grow w-full">
                    <p className="text-indigo-700 mb-4 p-4 bg-white rounded-lg border border-indigo-200">{practiceEvaluationResult.summary_vi}</p>
                    {practiceEvaluationResult.overallScore >= 65 ? (
                        <div className="p-4 bg-green-100 border-l-4 border-green-500 text-green-800 rounded-r-lg">
                            <h4 className="font-bold">Excellent Work!</h4>
                            <p className="text-sm">You've surpassed the <strong>65-point</strong> benchmark (Band 6.0). You are well-prepared for the Test Mode!</p>
                        </div>
                    ) : (
                        <div className="p-4 bg-yellow-100 border-l-4 border-yellow-500 text-yellow-800 rounded-r-lg">
                            <h4 className="font-bold">Keep Practicing!</h4>
                            <p className="text-sm">You're making progress. Continue practicing to reach the <strong>65-point</strong> benchmark to be ready for the test.</p>
                        </div>
                    )}
                </div>
            </div>
             <div className="text-center mt-6 flex justify-center gap-4">
                <button 
                    onClick={handleStartRecording} 
                    className="text-sm font-semibold text-primary hover:underline"
                >
                    Practice Again
                </button>
                {audioURL && (
                   <a 
                     href={audioURL} 
                     download="practice-recording.webm"
                     className="text-sm font-semibold text-secondary hover:underline flex items-center gap-1"
                   >
                     <DownloadIcon />
                     Tải audio vừa ghi
                   </a>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

