import { VALID_STUDENT_CODES } from '../config';
import type { Student } from '../types';

/**
 * Initializes the list of valid student codes.
 * Always relies on the VALID_STUDENT_CODES from config.ts to ensure
 * that any developer-side removals take effect immediately.
 * @returns {Set<string>} A set of uppercased student codes for efficient lookup.
 */
const initializeStudentCodes = (): Set<string> => {
  // We use the config directly as the source of truth for allowed codes.
  return new Set(VALID_STUDENT_CODES.map(code => code.toUpperCase()));
};

const validStudentCodes = initializeStudentCodes();

/**
 * Checks if a given student code is valid by comparing it against the current list.
 * The comparison is case-insensitive.
 * @param {string} code - The student code to validate.
 * @returns {boolean} True if the code is valid, false otherwise.
 */
export const isStudentValid = (code: string): boolean => {
  const upperCaseCode = code.trim().toUpperCase();
  if (!upperCaseCode) return false;
  return validStudentCodes.has(upperCaseCode);
};

import React, { useState, useMemo, useCallback } from 'react';
import { useAudioRecorder } from '../hooks/useAudioRecorder';
import { getTestEvaluation } from '../services/geminiService';
import { blobToBase64, getFriendlyErrorMessage } from '../App';
import type { TestEvaluationResult } from '../types';
import Loader from './Loader';
import { MicIcon } from './icons/MicIcon';
import { StopIcon } from './icons/StopIcon';
import TestResultDisplay from './TestResultDisplay';
import SoundWave from './SoundWave';


interface TestModeProps {
  onSwitchToPractice: () => void;
}

type TestStage = 'selectingPart' | 'recording' | 'evaluating' | 'showingResult';

const PartButton: React.FC<{ title: string, description: string, onClick: () => void }> = ({ title, description, onClick }) => (
    <button
        onClick={onClick}
        className="w-full text-left p-6 border-2 rounded-lg hover:border-primary/50 hover:bg-primary/5 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary transition-all duration-200"
    >
        <h4 className="text-xl font-bold text-dark">{title}</h4>
        <p className="text-secondary mt-1">{description}</p>
    </button>
);

const DownloadIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
);


const TestMode: React.FC<TestModeProps> = ({ onSwitchToPractice }) => {
    const [stage, setStage] = useState<TestStage>('selectingPart');
    const [testPart, setTestPart] = useState<'part1' | 'part2/3' | null>(null);
    const [question, setQuestion] = useState('');
    const [result, setResult] = useState<TestEvaluationResult | null>(null);
    const [error, setError] = useState<string | null>(null);
    const [evaluationTimestamp, setEvaluationTimestamp] = useState<string | null>(null);

    const { maxRecordingSeconds } = useMemo(() => {
        return testPart === 'part1' ? { maxRecordingSeconds: 45 } : { maxRecordingSeconds: 120 };
    }, [testPart]);

    const { recorderState, audioURL, audioBlob, startRecording: startAudioRecording, stopRecording: stopAudioRecording, resetRecording, error: recorderError, recordingTime, mediaStream } = useAudioRecorder({ maxRecordingSeconds });

    const formatTime = (seconds: number): string => {
        const minutes = Math.floor(seconds / 60);
        const remainingSeconds = seconds % 60;
        return `${minutes.toString().padStart(2, '0')}:${remainingSeconds.toString().padStart(2, '0')}`;
    };

    const handlePartSelect = (part: 'part1' | 'part2/3') => {
        setTestPart(part);
        setStage('recording');
        setError(null);
    };

    const startRecording = () => {
        setResult(null); // Clear previous results
        startAudioRecording();
    };

    const stopRecording = () => {
        stopAudioRecording();
    };

    const handleEvaluation = async (evaluationType: 'standard' | 'advanced') => {
        if (!audioBlob || !question.trim()) {
            setError("Please provide a question and a complete recording before submitting.");
            return;
        }
        setStage('evaluating');
        setError(null);

        try {
            const audioMimeType = audioBlob.type;
            const audioBase64 = await blobToBase64(audioBlob);
            const evaluationResult = await getTestEvaluation(audioBase64, audioMimeType, question, evaluationType);

            // Set timestamp
            const now = new Date();
            setEvaluationTimestamp(now.toLocaleString('en-US', {
                dateStyle: 'full',
                timeStyle: 'medium'
            }));

            setResult(evaluationResult);
            setStage('showingResult');
        } catch (err) {
            setError(getFriendlyErrorMessage(err));
            setStage('recording'); // Go back to recording stage on error
        }
    };

    const handleStartOver = () => {
        setStage('selectingPart');
        setTestPart(null);
        setQuestion('');
        setResult(null);
        setError(null);
        setEvaluationTimestamp(null);
        resetRecording();
    };

    const radius = 45;
    const circumference = 2 * Math.PI * radius;
    const progress = maxRecordingSeconds > 0 ? (recordingTime / maxRecordingSeconds) * 100 : 0;
    const offset = circumference - (progress / 100) * circumference;

    if (stage === 'selectingPart') {
        return (
            <div className="w-full max-w-4xl mx-auto bg-white p-8 rounded-xl shadow-lg text-center animate-fade-in">
                <h2 className="text-3xl font-bold text-dark mb-2">IELTS Speaking Test</h2>
                <p className="text-secondary mb-8 text-lg">Select which part of the test you want to perform.</p>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <PartButton title="Part 1" description="Answer short, personal questions." onClick={() => handlePartSelect('part1')} />
                    <PartButton title="Part 2 / 3" description="Give a monologue or discuss abstract topics." onClick={() => handlePartSelect('part2/3')} />
                </div>
            </div>
        );
    }

    if (stage === 'evaluating') {
        return (
            <div className="mt-8 bg-white p-6 rounded-xl shadow-lg flex flex-col items-center justify-center h-64">
                <Loader className="w-10 h-10 text-primary" />
                <p className="mt-4 text-secondary font-medium">Evaluating your speech... this may take a moment.</p>
            </div>
        );
    }

    if (stage === 'showingResult' && result) {
        return (
            <TestResultDisplay 
                result={result} 
                audioURL={audioURL} 
                timestamp={evaluationTimestamp}
                onStartOver={handleStartOver} 
                onSwitchToPractice={onSwitchToPractice} 
            />
        );
    }

    const isSubmitDisabled = !audioBlob || !question.trim() || recorderState !== 'finished';

    return (
        <div className="max-w-4xl mx-auto">
            <button 
                onClick={handleStartOver}
                className="mb-6 inline-flex items-center text-sm font-medium text-secondary hover:text-primary transition-colors"
                aria-label="Change test part"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 mr-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
              </svg>
              Change Test Part
            </button>
            <div className="bg-white p-6 rounded-xl shadow-lg space-y-6">
                <div>
                    <h2 className="text-2xl font-semibold text-dark">
                        Test: {testPart === 'part1' ? 'Part 1' : 'Part 2 / 3'}
                    </h2>
                     <p className="text-secondary mt-1">Enter the question or topic, then record your response below.</p>
                </div>

                 <div>
                    <label htmlFor="question-input" className="block text-sm font-medium text-gray-700 mb-1">Question / Topic</label>
                    <textarea
                        id="question-input"
                        value={question}
                        onChange={(e) => setQuestion(e.target.value)}
                        placeholder={testPart === 'part1' ? "E.g., What kind of music do you like?" : "E.g., Describe a memorable trip you have taken."}
                        className="w-full h-24 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary focus:border-transparent transition duration-200 resize-y"
                        disabled={recorderState === 'recording'}
                    />
                 </div>

                 <div className="border-t pt-6">
                    <h3 className="text-xl font-semibold text-dark mb-4">Record Your Response</h3>
                     <div className="p-4 bg-gray-100 rounded-lg">
                        {recorderState === 'recording' ? (
                            <div className="w-full flex flex-col sm:flex-row items-center justify-center gap-6">
                                {/* Timer Circle */}
                                <div className="relative w-24 h-24 flex-shrink-0">
                                    <svg className="w-full h-full" viewBox="0 0 100 100">
                                        <circle className="text-gray-300" strokeWidth="8" stroke="currentColor" fill="transparent" r={radius} cx="50" cy="50"/>
                                        <circle
                                            className="text-danger"
                                            strokeWidth="8"
                                            strokeLinecap="round"
                                            stroke="currentColor"
                                            fill="transparent"
                                            r={radius}
                                            cx="50"
                                            cy="50"
                                            style={{
                                                strokeDasharray: circumference,
                                                strokeDashoffset: offset,
                                                transform: 'rotate(-90deg)',
                                                transformOrigin: '50% 50%',
                                                transition: 'stroke-dashoffset 0.5s linear',
                                            }}
                                        />
                                    </svg>
                                    <div className="absolute inset-0 flex items-center justify-center">
                                        <span className="font-mono text-xl font-bold text-dark">{formatTime(recordingTime)}</span>
                                    </div>
                                </div>

                                {/* Sound Wave */}
                                <div className="w-full max-w-[200px] sm:max-w-[250px]">
                                    {mediaStream && <SoundWave 
                                        mediaStream={mediaStream} 
                                        width={250} 
                                        height={60} 
                                        baseColor="#FCA5A5"   
                                        activeColor="#DC3545" 
                                    />}
                                </div>

                                {/* Stop Button */}
                                <button onClick={stopRecording} className="flex items-center justify-center w-full sm:w-auto gap-2 px-6 py-3 bg-danger text-white font-bold rounded-lg hover:bg-red-600 transition duration-200 shrink-0">
                                    <StopIcon />
                                    <span>Stop Recording</span>
                                </button>
                            </div>
                        ) : (
                            <div className="flex flex-col sm:flex-row items-center gap-4">
                                <div className="flex items-center gap-3 w-full sm:w-auto">
                                  <button onClick={startRecording} className="flex items-center justify-center w-full sm:w-auto gap-2 px-6 py-3 bg-primary text-white font-bold rounded-lg hover:bg-blue-600 transition duration-200 shrink-0">
                                      <MicIcon />
                                      {recorderState === 'finished' ? 'Record Again' : 'Start Recording'}
                                  </button>
                                  {recorderState === 'finished' && audioURL && (
                                     <a 
                                       href={audioURL} 
                                       download="test-recording.webm"
                                       className="flex items-center justify-center gap-2 px-4 py-3 bg-white border border-secondary text-secondary font-bold rounded-lg hover:bg-gray-50 transition duration-200"
                                       title="Tải audio bài thi vừa ghi"
                                     >
                                       <DownloadIcon />
                                       <span>Tải audio</span>
                                     </a>
                                  )}
                                </div>

                                {audioURL && (
                                    <div className="w-full flex items-center gap-2 p-2 bg-white rounded-md border shadow-sm">
                                    <audio src={audioURL} controls className="w-full" aria-label="Your audio recording" />
                                    </div>
                                )}
                            </div>
                        )}
                         {(recorderError || error) && (
                            <div className="mt-3 text-red-600 text-sm" role="alert">
                                {recorderError || error}
                            </div>
                        )}
                    </div>
                </div>

                <div className="border-t pt-6">
                    <h3 className="text-xl font-semibold mb-2 text-dark">Submit for Evaluation</h3>
                    <p className="text-secondary mb-4">Choose an evaluation type. Both use strict IELTS scoring, but provide different levels of feedback.</p>
                    <div className="flex flex-col sm:flex-row gap-4">
                        <div className="w-full">
                            <button
                                onClick={() => handleEvaluation('standard')}
                                disabled={isSubmitDisabled}
                                className="w-full flex justify-center items-center bg-success text-white font-bold py-3 px-4 rounded-lg hover:bg-green-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-success disabled:bg-gray-400 disabled:cursor-not-allowed transition duration-200"
                            >
                                Standard Evaluation
                            </button>
                            <p className="text-xs text-secondary mt-2 px-1 text-center sm:text-left">
                                Provides a simpler, more accessible revised script. Ideal for intermediate learners.
                            </p>
                        </div>
                        <div className="w-full">
                            <button
                                onClick={() => handleEvaluation('advanced')}
                                disabled={isSubmitDisabled}
                                className="w-full flex justify-center items-center bg-white border border-secondary text-secondary font-bold py-3 px-4 rounded-lg hover:bg-secondary/10 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-secondary disabled:bg-gray-400 disabled:text-white disabled:border-gray-400 disabled:cursor-not-allowed transition duration-200"
                            >
                                Advanced Evaluation
                            </button>
                            <p className="text-xs text-secondary mt-2 px-1 text-center sm:text-left">
                                Provides a more sophisticated, high-level revised script for advanced learners.
                            </p>
                        </div>
                    </div>
                     <p className="text-xs text-secondary mt-4 text-center">
                        You must enter a question and record your audio before you can submit.
                    </p>
                </div>
            </div>
        </div>
    );
};

export default TestMode;

import React, { useRef } from 'react';
import type { TestEvaluationResult } from '../types';
import ScoreCircle from './ScoreCircle';

// Let TypeScript know that html2canvas is available on the window object
declare var html2canvas: any;

interface TestResultDisplayProps {
    result: TestEvaluationResult;
    audioURL: string | null;
    timestamp: string | null;
    onStartOver: () => void;
    onSwitchToPractice: () => void;
}

// Icons for sections
const CriteriaIcon = () => <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" /></svg>;
const ScriptIcon = () => <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>;
const AudioIcon = () => <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" /></svg>;
const ThumbsUpIcon = () => <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 inline mr-1.5 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M14 10h4.764a2 2 0 011.789 2.894l-3.5 7A2 2 0 0115.263 21h-4.017c-.163 0-.326-.02-.485-.06L7 20m7-10V5a2 2 0 00-2-2h-.085a2 2 0 00-1.736.97l-2.714 4.224a2 2 0 01-1.226 1.006H4V20h3v-8.571L14 10z" /></svg>;
const ThumbsDownIcon = () => <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 inline mr-1.5 text-red-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M10 14H5.236a2 2 0 01-1.789-2.894l3.5-7A2 2 0 018.738 3h4.017c.163 0 .326.02.485.06L17 4m-7 10v5a2 2 0 002 2h.085a2 2 0 001.736-.97l2.714-4.224a2 2 0 011.226-1.006H20V4h-3v8.571L10 14z" /></svg>;


const CriteriaCard: React.FC<{ title: string; title_vi: string; feedback: string }> = ({ title, title_vi, feedback }) => {
    // Helper function to parse a section (strengths or weaknesses)
    const parseSection = (text: string | undefined): string[] => {
        if (!text) return [];
        return text
            .split('\n')
            .map(line => line.trim())
            .filter(line => line.startsWith('-'))
            .map(line => line.substring(1).trim())
            .filter(Boolean); // Also remove empty strings after trimming
    };

    // Use a regex that is case-insensitive and handles potential whitespace
    const parts = feedback.split(/Điểm\s+yếu:/i);
    const strengthsText = parts[0];
    const weaknessesText = parts.length > 1 ? parts[1] : undefined;

    const strengths = parseSection(strengthsText?.replace(/Điểm\s+mạnh:/i, ''));
    const weaknesses = parseSection(weaknessesText);

    return (
        <div className="bg-white p-4 rounded-lg border h-full flex flex-col">
            <h4 className="font-semibold text-gray-800">{title}</h4>
            <p className="text-sm text-secondary mb-3">{title_vi}</p>
            <div className="flex-grow space-y-4">
                {strengths.length > 0 && (
                    <div>
                        <h5 className="font-semibold text-sm text-green-700 flex items-center">
                            <ThumbsUpIcon />
                            Điểm mạnh (Strengths)
                        </h5>
                        <ul className="list-disc list-inside text-sm text-dark space-y-1.5 mt-2 pl-2">
                            {strengths.map((item, index) => <li key={`s-${index}`}>{item}</li>)}
                        </ul>
                    </div>
                )}
                {weaknesses.length > 0 && (
                    <div>
                        <h5 className="font-semibold text-sm text-red-700 flex items-center">
                            <ThumbsDownIcon />
                            Điểm yếu (Weaknesses)
                        </h5>
                        <ul className="list-disc list-inside text-sm text-dark space-y-1.5 mt-2 pl-2">
                            {weaknesses.map((item, index) => <li key={`w-${index}`}>{item}</li>)}
                        </ul>
                    </div>
                )}
                 {strengths.length === 0 && weaknesses.length === 0 && (
                     <p className="text-sm text-dark">{feedback}</p> // Fallback
                 )}
            </div>
        </div>
    );
};


const TestResultDisplay: React.FC<TestResultDisplayProps> = ({ result, audioURL, timestamp, onStartOver, onSwitchToPractice }) => {
    const resultsRef = useRef<HTMLDivElement>(null);

    const handleExportAsImage = () => {
        const elementToCapture = resultsRef.current;
        if (elementToCapture && typeof html2canvas !== 'undefined') {
            html2canvas(elementToCapture, {
                useCORS: true,
                scale: 2, // Higher scale for better quality
                backgroundColor: '#f9fafb', // Match the bg-gray-50
                scrollY: -window.scrollY // Account for the user scrolling down the page
            }).then((canvas: HTMLCanvasElement) => {
                const link = document.createElement('a');
                link.download = 'speakwise-test-result.png';
                link.href = canvas.toDataURL('image/png');
                link.click();
            }).catch((err: any) => {
                console.error("Failed to export image:", err);
                alert("Sorry, there was an error exporting your results as an image.");
            });
        } else {
             alert("The export feature is currently unavailable. Please try again later.");
        }
    };

    const suggestionsList = result.suggestions_vi
        .split('\n')
        .map(item => item.trim())
        .filter(item => item.startsWith('-'))
        .map(item => item.substring(1).trim())
        .filter(Boolean);

    const showRepracticeRecommendation = result.overallScore <= 60;

    return (
        <div className="w-full max-w-4xl mx-auto animate-fade-in space-y-8">
            <div ref={resultsRef} className="bg-gray-50 p-6 sm:p-8 rounded-xl shadow-lg space-y-8">
                <h2 className="text-3xl font-bold text-dark text-center">Your Test Results</h2>

                {timestamp && (
                    <p className="text-center text-slate-500 font-medium -mt-6">
                        {timestamp}
                    </p>
                )}

                {/* Main Score & Summary Card */}
                <div className="bg-white p-6 rounded-xl shadow-md grid grid-cols-1 md:grid-cols-3 gap-6 items-center">
                    <div className="md:col-span-1">
                        <ScoreCircle score={result.overallScore} />
                    </div>
                    <div className="md:col-span-2">
                        <h3 className="text-xl font-semibold text-dark mb-2">Summary (Tổng kết)</h3>
                        <p className="text-dark border-l-4 border-primary bg-primary/5 p-4 rounded-r-lg">{result.summary_vi}</p>
                    </div>
                </div>

                {/* Suggestions Card */}
                <div className="bg-white p-6 rounded-xl shadow-md">
                    <h3 className="text-xl font-semibold text-dark mb-4">💡 Suggestions for Improvement (Gợi ý cải thiện)</h3>
                    <div className="space-y-3">
                        {suggestionsList.length > 0 ? (
                            suggestionsList.map((suggestion, index) => (
                                <div key={index} className="flex items-start p-4 bg-primary/5 border-l-4 border-primary rounded-md shadow-sm">
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 mr-3 text-primary shrink-0 mt-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                                        <path strokeLinecap="round" strokeLinejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" />
                                    </svg>
                                    <p className="text-sm text-dark font-medium">{suggestion}</p>
                                </div>
                            ))
                        ) : (
                            <p className="text-sm text-gray-700">{result.suggestions_vi}</p>
                        )}
                    </div>
                </div>

                {/* Detailed Analysis */}
                <div className="bg-white p-6 rounded-xl shadow-md">
                    <h3 className="text-2xl font-bold text-dark mb-4">Detailed Analysis</h3>
                    <div className="space-y-8">
                        {/* --- Criteria Section --- */}
                        <div>
                             <h4 className="text-xl font-semibold text-dark mb-3 flex items-center"><CriteriaIcon /> IELTS Criteria</h4>
                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <CriteriaCard title="Fluency & Coherence" title_vi="Độ trôi chảy và mạch lạc" feedback={result.ieltsCriteriaFeedback.fluency_vi} />
                                <CriteriaCard title="Lexical Resource" title_vi="Vốn từ vựng" feedback={result.ieltsCriteriaFeedback.lexicalResource_vi} />
                                <CriteriaCard title="Grammatical Range & Accuracy" title_vi="Ngữ pháp" feedback={result.ieltsCriteriaFeedback.grammaticalRangeAndAccuracy_vi} />
                                <CriteriaCard title="Pronunciation" title_vi="Phát âm" feedback={result.ieltsCriteriaFeedback.pronunciation_vi} />
                             </div>
                        </div>

                        {/* --- Script Section --- */}
                        <div className="border-t pt-6">
                             <h4 className="text-xl font-semibold text-dark mb-3 flex items-center"><ScriptIcon /> Script Comparison</h4>
                            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                                <div>
                                    <h5 className="font-semibold text-gray-800 mb-2">Your Transcribed Speech</h5>
                                     <div className="bg-gray-50 p-4 border-l-4 border-secondary rounded-r-lg h-full">
                                        <p className="text-dark whitespace-pre-wrap leading-relaxed text-sm">{result.transcribedScript || "No speech was transcribed."}</p>
                                     </div>
                                </div>
                                 {result.improvedScript && (
                                     <div>
                                        <h5 className="font-semibold text-gray-800 mb-2">AI Suggested Improvement</h5>
                                        <div className="bg-green-50 p-4 border-l-4 border-success rounded-r-lg h-full">
                                            <p className="text-dark whitespace-pre-wrap leading-relaxed text-sm">{result.improvedScript}</p>
                                        </div>
                                    </div>
                                 )}
                             </div>
                        </div>

                         {/* --- Audio Section --- */}
                         {audioURL && (
                            <div className="border-t pt-6">
                                 <h4 className="text-xl font-semibold text-dark mb-3 flex items-center"><AudioIcon /> Your Recording</h4>
                                <audio src={audioURL} controls className="w-full" aria-label="Your audio recording" />
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Recommendation & Actions */}
            <div className="space-y-6">
                {showRepracticeRecommendation && (
                    <div className="p-4 bg-yellow-50 border-l-4 border-yellow-400 text-yellow-800 rounded-lg shadow-md">
                        <h4 className="font-bold">Recommendation</h4>
                        <p className="mt-1 text-sm">Your score suggests there are key areas to improve. We recommend you re-practice this content in the 'Practice' tab to get detailed feedback and improve your script.</p>
                        <button
                            onClick={onSwitchToPractice}
                            className="mt-3 bg-yellow-400 text-yellow-900 font-bold py-2 px-4 rounded-lg hover:bg-yellow-500 transition-colors"
                        >
                            Go to Practice Tab
                        </button>
                    </div>
                )}
                 <div className="bg-white p-6 rounded-xl shadow-lg flex flex-col md:flex-row items-center justify-between gap-4">
                    <h3 className="text-lg font-semibold text-dark">Manage Your Results</h3>
                    <div className="flex flex-col sm:flex-row gap-4 w-full sm:w-auto">
                        {audioURL && (
                            <a 
                                href={audioURL} 
                                download="speakwise-recording.m4a"
                                className="w-full sm:w-auto text-center bg-white border border-secondary text-secondary font-bold py-2 px-4 rounded-lg hover:bg-secondary/10 transition duration-200"
                            >
                                Download Audio
                            </a>
                        )}
                        <button
                            onClick={handleExportAsImage}
                            className="w-full sm:w-auto bg-white border border-primary text-primary font-bold py-2 px-4 rounded-lg hover:bg-primary/10 transition duration-200"
                        >
                            Export as Photo
                        </button>
                    </div>
                </div>

                <div className="pt-2 text-center">
                    <button
                        onClick={onStartOver}
                        className="w-full md:w-auto flex justify-center items-center mx-auto bg-primary text-white font-bold py-3 px-8 rounded-lg hover:bg-blue-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary transition duration-200"
                    >
                        Take Another Test
                    </button>
                </div>
            </div>
        </div>
    );
};

export default TestResultDisplay;
